"use client";

import { useEffect, useState } from "react";
import { Megaphone, Plus, X, Mail, MessageSquare, Calendar, TrendingUp } from "lucide-react";
import { useToast } from "@/components/ui/Toast";

interface Campaign {
  id: string;
  name: string;
  subject?: string | null;
  status: string;
  sentCount: number;
  failedCount: number;
  skippedCount: number;
  scheduledFor?: string | null;
  createdAt: string;
  channel: string;
  targetAudience: string;
}

interface QueueBreakdown {
  pending: number;
  processing: number;
  retry: number;
  sent: number;
  failed: number;
  totalActive: number;
}

export default function GarageCampaignsPage() {
  const { addToast } = useToast();
  const [showModal, setShowModal] = useState(false);
  const [campaignName, setCampaignName] = useState("");
  const [campaignSubject, setCampaignSubject] = useState("");
  const [campaignChannel, setCampaignChannel] = useState<"email" | "sms">("email");
  const [campaignMessage, setCampaignMessage] = useState("");
  const [scheduleDate, setScheduleDate] = useState("");
  const [targetAudience, setTargetAudience] = useState("all");
  const [garageId, setGarageId] = useState<string | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [loadingCampaigns, setLoadingCampaigns] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isCreating, setIsCreating] = useState(false);
  const [queueTotals, setQueueTotals] = useState<QueueBreakdown>({
    pending: 0,
    processing: 0,
    retry: 0,
    sent: 0,
    failed: 0,
    totalActive: 0,
  });
  const [queueByCampaign, setQueueByCampaign] = useState<Record<string, QueueBreakdown>>({});

  const fetchQueueStatus = async (garage: string) => {
    const res = await fetch(`/api/campaigns/queue-status?garageId=${garage}`, { cache: "no-store" });
    if (res.ok) {
      const data = await res.json();
      setQueueTotals(data.totals || {
        pending: 0,
        processing: 0,
        retry: 0,
        sent: 0,
        failed: 0,
        totalActive: 0,
      });
      setQueueByCampaign(data.byCampaign || {});
    }
  };

  const formatDate = (value?: string | null) => {
    if (!value) return "-";
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return "-";
    return date.toISOString().slice(0, 10);
  };

  const fetchCampaigns = async (garage: string) => {
    const res = await fetch(`/api/campaigns?garageId=${garage}`);
    if (res.ok) {
      const data = await res.json();
      setCampaigns(data);
    }
  };

  const processScheduled = async (garage: string) => {
    setIsProcessing(true);
    try {
      await fetch(`/api/campaigns/process?garageId=${garage}`, {
        method: "POST",
      });
    } finally {
      setIsProcessing(false);
    }
  };

  useEffect(() => {
    const loadGarageId = async () => {
      const res = await fetch("/api/garages");
      const garages = await res.json();
      if (garages[0]) {
        setGarageId(garages[0].id);
      }
    };
    loadGarageId();
  }, []);

  useEffect(() => {
    if (!garageId) return;

    const loadCampaigns = async () => {
      setLoadingCampaigns(true);
      await processScheduled(garageId);
      await fetchCampaigns(garageId);
      await fetchQueueStatus(garageId);
      setLoadingCampaigns(false);
    };

    loadCampaigns();

    const interval = window.setInterval(() => {
      fetchCampaigns(garageId);
      fetchQueueStatus(garageId);
    }, 10000);

    return () => window.clearInterval(interval);
  }, [garageId]);

  const handleCreateCampaign = async () => {
    if (!garageId) {
      addToast("Garage not found. Please refresh and try again.", "error");
      return;
    }

    if (!campaignName || !campaignMessage) {
      addToast("Please fill in campaign name and message", "error");
      return;
    }

    if (campaignChannel === "sms") {
      addToast("SMS campaigns are coming soon. Please use email for now.", "error");
      return;
    }

    setIsCreating(true);

    try {
      const response = await fetch("/api/campaigns", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          garageId,
          name: campaignName,
          subject: campaignSubject,
          channel: campaignChannel,
          message: campaignMessage,
          targetAudience,
          scheduledFor: scheduleDate || undefined,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        addToast(data.error || "Failed to create campaign", "error");
        return;
      }

      addToast(`Campaign "${campaignName}" created successfully!`, "success");
      setShowModal(false);
      setCampaignName("");
      setCampaignSubject("");
      setCampaignMessage("");
      setScheduleDate("");
      setTargetAudience("all");
      await fetchCampaigns(garageId);
      await fetchQueueStatus(garageId);
    } finally {
      setIsCreating(false);
    }
  };

  const activeCount = campaigns.filter((campaign) =>
    ["SENDING", "SCHEDULED"].includes(campaign.status)
  ).length;
  const sentTotal = queueTotals.sent;
  const scheduledTotal = campaigns.filter((campaign) => campaign.status === "SCHEDULED").length;
  const failedTotal = queueTotals.failed;

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-slate-900">Marketing Campaigns</h1>
          <p className="text-slate-600 mt-1">Schedule and track your customer campaigns</p>
        </div>
        <button
          onClick={() => setShowModal(true)}
          className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2.5 rounded-lg font-semibold transition-colors"
        >
          <Plus size={20} />
          New Campaign
        </button>
      </header>

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-white border border-slate-200 rounded-xl p-5">
          <Megaphone className="text-blue-600 mb-3" size={24} />
          <p className="text-2xl font-bold text-slate-900">{activeCount}</p>
          <p className="text-sm text-slate-600">Active Campaigns</p>
        </div>
        <div className="bg-white border border-slate-200 rounded-xl p-5">
          <Mail className="text-emerald-600 mb-3" size={24} />
          <p className="text-2xl font-bold text-slate-900">{sentTotal}</p>
          <p className="text-sm text-slate-600">Messages Sent</p>
        </div>
        <div className="bg-white border border-slate-200 rounded-xl p-5">
          <TrendingUp className="text-amber-600 mb-3" size={24} />
          <p className="text-2xl font-bold text-slate-900">{failedTotal}</p>
          <p className="text-sm text-slate-600">Failed Sends</p>
        </div>
        <div className="bg-white border border-slate-200 rounded-xl p-5">
          <Calendar className="text-purple-600 mb-3" size={24} />
          <p className="text-2xl font-bold text-slate-900">{scheduledTotal}</p>
          <p className="text-sm text-slate-600">Scheduled</p>
        </div>
      </div>

      <div className="bg-white border border-slate-200 rounded-xl p-5">
        <div className="flex items-center justify-between mb-4">
          <h3 className="font-bold text-slate-900">Delivery Queue Status</h3>
          <button
            onClick={() => {
              if (!garageId) return;
              fetchCampaigns(garageId);
              fetchQueueStatus(garageId);
            }}
            className="px-3 py-1.5 text-xs font-semibold bg-slate-100 text-slate-700 rounded-lg hover:bg-slate-200"
          >
            Refresh
          </button>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-6 gap-3">
          <div className="rounded-lg border border-amber-200 bg-amber-50 p-3">
            <p className="text-xs text-amber-700 font-semibold">Pending</p>
            <p className="text-xl font-bold text-amber-800">{queueTotals.pending}</p>
          </div>
          <div className="rounded-lg border border-blue-200 bg-blue-50 p-3">
            <p className="text-xs text-blue-700 font-semibold">Processing</p>
            <p className="text-xl font-bold text-blue-800">{queueTotals.processing}</p>
          </div>
          <div className="rounded-lg border border-purple-200 bg-purple-50 p-3">
            <p className="text-xs text-purple-700 font-semibold">Retry</p>
            <p className="text-xl font-bold text-purple-800">{queueTotals.retry}</p>
          </div>
          <div className="rounded-lg border border-emerald-200 bg-emerald-50 p-3">
            <p className="text-xs text-emerald-700 font-semibold">Sent</p>
            <p className="text-xl font-bold text-emerald-800">{queueTotals.sent}</p>
          </div>
          <div className="rounded-lg border border-rose-200 bg-rose-50 p-3">
            <p className="text-xs text-rose-700 font-semibold">Failed</p>
            <p className="text-xl font-bold text-rose-800">{queueTotals.failed}</p>
          </div>
          <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
            <p className="text-xs text-slate-700 font-semibold">Active</p>
            <p className="text-xl font-bold text-slate-800">{queueTotals.totalActive}</p>
          </div>
        </div>
      </div>

      {/* Campaigns List */}
      <div className="bg-white border border-slate-200 rounded-xl overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-200">
          <h3 className="font-bold text-slate-900">Your Campaigns</h3>
        </div>
        <table className="w-full">
          <thead className="bg-slate-50 border-b border-slate-200">
            <tr className="text-slate-600 text-xs uppercase tracking-wider font-semibold">
              <th className="px-6 py-3 text-left">Campaign</th>
              <th className="px-6 py-3 text-left">Status</th>
              <th className="px-6 py-3 text-left">Sent</th>
              <th className="px-6 py-3 text-left">Skipped</th>
              <th className="px-6 py-3 text-left">Failed</th>
              <th className="px-6 py-3 text-left">Queue</th>
              <th className="px-6 py-3 text-left">Date</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-200">
            {loadingCampaigns ? (
              <tr>
                <td colSpan={7} className="px-6 py-6 text-center text-slate-500">
                  {isProcessing ? "Processing scheduled campaigns..." : "Loading campaigns..."}
                </td>
              </tr>
            ) : campaigns.length === 0 ? (
              <tr>
                <td colSpan={7} className="px-6 py-6 text-center text-slate-500">
                  No campaigns yet. Create your first campaign to start sending.
                </td>
              </tr>
            ) : (
              campaigns.map((campaign) => (
                <tr key={campaign.id} className="hover:bg-slate-50">
                  <td className="px-6 py-4 font-medium text-slate-900">{campaign.name}</td>
                  <td className="px-6 py-4">
                    <span
                      className={`px-2.5 py-1 rounded-full text-xs font-semibold ${
                        campaign.status === "COMPLETED"
                          ? "bg-emerald-100 text-emerald-700"
                          : campaign.status === "FAILED"
                          ? "bg-rose-100 text-rose-700"
                          : "bg-amber-100 text-amber-700"
                      }`}
                    >
                      {campaign.status.toLowerCase()}
                    </span>
                  </td>
                  <td className="px-6 py-4 text-slate-700">{campaign.sentCount}</td>
                  <td className="px-6 py-4 text-slate-700">{campaign.skippedCount}</td>
                  <td className="px-6 py-4 text-slate-700">{campaign.failedCount}</td>
                  <td className="px-6 py-4 text-xs text-slate-700">
                    {(() => {
                      const queue = queueByCampaign[campaign.id] || {
                        pending: 0,
                        processing: 0,
                        retry: 0,
                        sent: 0,
                        failed: 0,
                        totalActive: 0,
                      };
                      return `P:${queue.pending} • R:${queue.retry} • PR:${queue.processing} • S:${queue.sent} • F:${queue.failed}`;
                    })()}
                  </td>
                  <td className="px-6 py-4 text-slate-600">
                    {formatDate(campaign.scheduledFor || campaign.createdAt)}
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {/* Campaign Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="p-6 border-b border-slate-200 flex items-center justify-between sticky top-0 bg-white">
              <h2 className="text-2xl font-bold text-slate-900">Create Campaign</h2>
              <button onClick={() => setShowModal(false)} className="text-slate-400 hover:text-slate-600">
                <X size={24} />
              </button>
            </div>

            <div className="p-6 space-y-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Campaign Name *</label>
                <input
                  type="text"
                  value={campaignName}
                  onChange={(e) => setCampaignName(e.target.value)}
                  placeholder="e.g., March MOT Reminders"
                  className="w-full border border-slate-300 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Email Subject (Optional)</label>
                <input
                  type="text"
                  value={campaignSubject}
                  onChange={(e) => setCampaignSubject(e.target.value)}
                  placeholder="e.g., 20% off servicing this month"
                  className="w-full border border-slate-300 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                <p className="text-xs text-slate-500 mt-1">Defaults to campaign name if left blank.</p>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-3">Channel *</label>
                <div className="grid grid-cols-2 gap-3">
                  <button
                    onClick={() => setCampaignChannel("email")}
                    className={`p-4 rounded-lg border transition-all ${
                      campaignChannel === "email"
                        ? "bg-blue-50 border-blue-500 text-blue-600"
                        : "border-slate-200 hover:border-slate-300"
                    }`}
                  >
                    <Mail className="mx-auto mb-2" size={24} />
                    <p className="text-sm font-medium">Email</p>
                  </button>
                  <button
                    onClick={() => setCampaignChannel("sms")}
                    disabled
                    className="p-4 rounded-lg border border-slate-200 opacity-50 cursor-not-allowed"
                  >
                    <MessageSquare className="mx-auto mb-2" size={24} />
                    <p className="text-sm font-medium">SMS (coming soon)</p>
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Target Audience</label>
                <select
                  value={targetAudience}
                  onChange={(e) => setTargetAudience(e.target.value)}
                  className="w-full border border-slate-300 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="all">All Customers</option>
                  <option value="mot_expiring">MOT Expiring Soon</option>
                  <option value="service_due">Service Due</option>
                  <option value="inactive">Inactive (90+ days)</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Schedule Date (Optional)</label>
                <input
                  type="datetime-local"
                  value={scheduleDate}
                  onChange={(e) => setScheduleDate(e.target.value)}
                  className="w-full border border-slate-300 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">
                  Message * {campaignChannel === "sms" && `(${campaignMessage.length}/160)`}
                </label>
                <textarea
                  value={campaignMessage}
                  onChange={(e) => {
                    if (campaignChannel === "sms" && e.target.value.length > 160) return;
                    setCampaignMessage(e.target.value);
                  }}
                  rows={campaignChannel === "email" ? 8 : 4}
                  className="w-full border border-slate-300 rounded-lg px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none"
                />
              </div>

              <div className="flex gap-3 pt-4">
                <button
                  onClick={handleCreateCampaign}
                  disabled={isCreating}
                  className="flex-1 bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-lg font-semibold disabled:opacity-60"
                >
                  {isCreating
                    ? "Creating..."
                    : scheduleDate
                    ? "Schedule Campaign"
                    : "Create & Send Now"}
                </button>
                <button
                  onClick={() => setShowModal(false)}
                  className="px-6 py-3 rounded-lg font-semibold border border-slate-300 hover:bg-slate-50"
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
